/**
 * TDD tests for the error-retry pipeline.
 *
 * Approach: We build the pipeline incrementally using red/green/refactor cycles.
 * Each test is written FIRST (red), then we write minimal code to pass (green),
 * then refactor. Uses Node 20's built-in test runner (no dependencies).
 */

import { describe, it } from "node:test";
import assert from "node:assert/strict";

// =============================================================================
// TDD CYCLE 1: Basic Queue — enqueue items and dequeue them in FIFO order
// =============================================================================

describe("Queue", () => {
  it("should enqueue and dequeue in FIFO order", async () => {
    const { Queue } = await import("./pipeline.mjs");
    const q = new Queue();
    q.enqueue("a");
    q.enqueue("b");
    q.enqueue("c");

    assert.equal(q.dequeue(), "a");
    assert.equal(q.dequeue(), "b");
    assert.equal(q.dequeue(), "c");
  });

  it("should return undefined when dequeuing from empty queue", async () => {
    const { Queue } = await import("./pipeline.mjs");
    const q = new Queue();
    assert.equal(q.dequeue(), undefined);
  });

  it("should report its size", async () => {
    const { Queue } = await import("./pipeline.mjs");
    const q = new Queue();
    assert.equal(q.size(), 0);
    q.enqueue(1);
    q.enqueue(2);
    assert.equal(q.size(), 2);
    q.dequeue();
    assert.equal(q.size(), 1);
  });

  it("should report whether it is empty", async () => {
    const { Queue } = await import("./pipeline.mjs");
    const q = new Queue();
    assert.equal(q.isEmpty(), true);
    q.enqueue("x");
    assert.equal(q.isEmpty(), false);
  });

  it("should return all items as an array", async () => {
    const { Queue } = await import("./pipeline.mjs");
    const q = new Queue();
    q.enqueue("a");
    q.enqueue("b");
    assert.deepEqual(q.items(), ["a", "b"]);
  });
});

