 49→    assert.equal(q.size(), 0);
 50→    q.enqueue(1);
 51→    q.enqueue(2);
 52→    assert.equal(q.size(), 2);
 53→    q.dequeue();
 54→    assert.equal(q.size(), 1);
 55→  });
 56→
 57→  it("should report whether it is empty", () => {
 58→    assert.equal(q.isEmpty(), true);
 59→    q.enqueue("x");
 60→    assert.equal(q.isEmpty(), false);
 61→  });
 62→
 63→  it("should return all items as an array snapshot", () => {
