 70→    const q2 = new Queue(["x", "y", "z"]);
 71→    assert.equal(q2.size(), 3);
 72→    assert.equal(q2.dequeue(), "x");
 73→  });
 74→});
 75→
 76→// =============================================================================
 77→// TDD CYCLE 2 (RED→GREEN): Exponential Backoff — compute delay for each retry
 78→// The retry strategy needs to be pluggable. ExponentialBackoff computes the
 79→// delay (in ms) for a given attempt number with configurable base and cap.
 80→// =============================================================================
 81→
 82→describe("ExponentialBackoff", () => {
 83→  it("should compute delay as base * 2^attempt", () => {
 84→    // Default base = 100ms
 85→    const backoff = new ExponentialBackoff({ baseMs: 100 });
 86→    assert.equal(backoff.delay(0), 100); // 100 * 2^0 = 100
 87→    assert.equal(backoff.delay(1), 200); // 100 * 2^1 = 200
 88→    assert.equal(backoff.delay(2), 400); // 100 * 2^2 = 400
 89→    assert.equal(backoff.delay(3), 800); // 100 * 2^3 = 800
 90→  });
 91→
 92→  it("should cap the delay at maxMs", () => {
 93→    const backoff = new ExponentialBackoff({ baseMs: 100, maxMs: 500 });
 94→    assert.equal(backoff.delay(0), 100);
 95→    assert.equal(backoff.delay(3), 500); // would be 800 but capped at 500
 96→    assert.equal(backoff.delay(10), 500); // still capped
 97→  });
 98→
 99→  it("should use sensible defaults", () => {
100→    const backoff = new ExponentialBackoff();
101→    // Default: baseMs=100, maxMs=30000
102→    assert.equal(backoff.delay(0), 100);
103→    assert.equal(backoff.delay(20), 30000); // capped at default max
104→  });
105→});
106→
107→// =============================================================================
108→// TDD CYCLE 3 (RED→GREEN): Dead-Letter Queue — record failed items with metadata
109→// Items that exhaust all retries go here with the error details.
110→// =============================================================================
111→
112→describe("DeadLetterQueue", () => {
113→  it("should add failed items with error and attempt count", () => {
114→    const dlq = new DeadLetterQueue();
115→    const error = new Error("kaboom");
116→    dlq.add({ id: 1, data: "test" }, error, 3);
117→
118→    const entries = dlq.entries();
119→    assert.equal(entries.length, 1);
120→    assert.deepEqual(entries[0].item, { id: 1, data: "test" });
121→    assert.equal(entries[0].error.message, "kaboom");
122→    assert.equal(entries[0].attempts, 3);
123→    assert.ok(entries[0].timestamp instanceof Date);
124→  });
125→
126→  it("should report its size", () => {
127→    const dlq = new DeadLetterQueue();
128→    assert.equal(dlq.size(), 0);
129→    dlq.add("item1", new Error("e1"), 1);
130→    dlq.add("item2", new Error("e2"), 2);
131→    assert.equal(dlq.size(), 2);
132→  });
133→
134→  it("should indicate whether it is empty", () => {
135→    const dlq = new DeadLetterQueue();
136→    assert.equal(dlq.isEmpty(), true);
137→    dlq.add("item", new Error("err"), 1);
138→    assert.equal(dlq.isEmpty(), false);
139→  });
140→});
141→
142→// =============================================================================
143→// TDD CYCLE 4 (RED→GREEN): Pipeline — process all items successfully
144→// The simplest pipeline scenario: every item processes without error.
145→// =============================================================================
146→
147→describe("Pipeline — all items succeed", () => {
148→  it("should process every item and report correct summary", async () => {
149→    const source = new Queue(["a", "b", "c"]);
150→    // Mock processor that always succeeds
151→    const processor = mock.fn(async (item) => `processed:${item}`);
152→
153→    const pipeline = new Pipeline({
154→      source,
155→      processor,
156→      maxRetries: 3,
157→      backoff: new ExponentialBackoff({ baseMs: 0 }), // no delay in tests
158→    });
159→
160→    const summary = await pipeline.run();
161→
162→    assert.equal(summary.totalItems, 3);
163→    assert.equal(summary.processed, 3);
164→    assert.equal(summary.failed, 0);
165→    assert.equal(summary.retried, 0);
166→    assert.equal(summary.deadLettered, 0);
167→    assert.equal(processor.mock.calls.length, 3);
168→  });
169→});
170→
171→// =============================================================================
172→// TDD CYCLE 5 (RED→GREEN): Pipeline — retry on transient failures
173→// Items that fail should be retried up to maxRetries times with backoff.
174→// =============================================================================
175→
176→describe("Pipeline — retry on transient failure", () => {
177→  it("should retry a failing item and succeed on later attempt", async () => {
178→    const source = new Queue(["flaky"]);
179→
180→    // Fail twice, then succeed on 3rd attempt
181→    let callCount = 0;
182→    const processor = async (item) => {
183→      callCount++;
184→      if (callCount <= 2) {
185→        throw new Error(`fail #${callCount}`);
186→      }
187→      return `ok:${item}`;
188→    };
189→
190→    const pipeline = new Pipeline({
191→      source,
192→      processor,
193→      maxRetries: 5,
194→      backoff: new ExponentialBackoff({ baseMs: 0 }),
195→    });
196→
197→    const summary = await pipeline.run();
198→
199→    assert.equal(summary.processed, 1);
200→    assert.equal(summary.failed, 0);
201→    assert.equal(summary.retried, 2); // 2 retries before success
202→    assert.equal(summary.deadLettered, 0);
203→    assert.equal(callCount, 3); // called 3 times total
204→  });
205→
206→  it("should apply exponential backoff between retries", async () => {
207→    const source = new Queue(["item"]);
208→    const delays = [];
209→
210→    // Custom sleep function to capture delays without actually waiting
211→    const sleepFn = async (ms) => {
212→      delays.push(ms);
213→    };
214→
215→    // Fail 3 times, then succeed
216→    let callCount = 0;
217→    const processor = async () => {
218→      callCount++;
219→      if (callCount <= 3) throw new Error("transient");
220→      return "ok";
221→    };
222→
223→    const pipeline = new Pipeline({
224→      source,
225→      processor,
226→      maxRetries: 5,
227→      backoff: new ExponentialBackoff({ baseMs: 100 }),
228→      sleepFn,
229→    });
230→
231→    await pipeline.run();
232→
233→    // Should have 3 delay calls: 100, 200, 400
234→    assert.equal(delays.length, 3);
235→    assert.equal(delays[0], 100);
236→    assert.equal(delays[1], 200);
237→    assert.equal(delays[2], 400);
238→  });
239→});
240→
241→// =============================================================================
242→// TDD CYCLE 6 (RED→GREEN): Pipeline — dead-letter queue for permanent failures
243→// Items that exhaust all retries should be moved to the dead-letter queue.
244→// =============================================================================
245→
246→describe("Pipeline — dead-letter queue", () => {
247→  it("should move permanently failing items to dead-letter queue", async () => {
248→    const source = new Queue(["doomed"]);
249→
250→    // Always fails
251→    const processor = async () => {
252→      throw new Error("permanent failure");
253→    };
254→
255→    const pipeline = new Pipeline({
256→      source,
257→      processor,
258→      maxRetries: 3,
259→      backoff: new ExponentialBackoff({ baseMs: 0 }),
260→    });
261→
262→    const summary = await pipeline.run();
263→
264→    assert.equal(summary.processed, 0);
265→    assert.equal(summary.failed, 1); // 1 item permanently failed
266→    assert.equal(summary.deadLettered, 1);
267→
268→    // Verify the DLQ contents
269→    const dlqEntries = pipeline.deadLetterQueue.entries();
270→    assert.equal(dlqEntries.length, 1);
271→    assert.equal(dlqEntries[0].item, "doomed");
272→    assert.equal(dlqEntries[0].error.message, "permanent failure");
273→    assert.equal(dlqEntries[0].attempts, 4); // 1 initial + 3 retries
274→  });
275→
276→  it("should handle mix of successful and failing items", async () => {
277→    const source = new Queue(["ok1", "bad", "ok2"]);
278→
279→    const processor = async (item) => {
280→      if (item === "bad") throw new Error("always fails");
281→      return `done:${item}`;
282→    };
283→
284→    const pipeline = new Pipeline({
285→      source,
286→      processor,
287→      maxRetries: 2,
288→      backoff: new ExponentialBackoff({ baseMs: 0 }),
289→    });
290→
291→    const summary = await pipeline.run();
292→
293→    assert.equal(summary.totalItems, 3);
294→    assert.equal(summary.processed, 2);
295→    assert.equal(summary.failed, 1);
296→    assert.equal(summary.deadLettered, 1);
297→  });
298→});
299→
300→// =============================================================================
301→// TDD CYCLE 7 (RED→GREEN): Pipeline — progress reporting
302→// The pipeline should emit progress events as items are processed.
303→// =============================================================================
304→
305→describe("Pipeline — progress reporting", () => {
306→  it("should report progress for each item outcome", async () => {
307→    const source = new Queue(["a", "b"]);
308→    const processor = mock.fn(async (item) => item);
309→    const progressEvents = [];
310→
311→    const pipeline = new Pipeline({
312→      source,
313→      processor,
314→      maxRetries: 3,
315→      backoff: new ExponentialBackoff({ baseMs: 0 }),
316→      onProgress: (event) => progressEvents.push(event),
317→    });
318→
319→    await pipeline.run();
320→
321→    // Should have 2 progress events (one per item, both succeed)
322→    assert.equal(progressEvents.length, 2);
323→
324→    // Each event should have the expected shape
325→    for (const event of progressEvents) {
326→      assert.ok("item" in event);
327→      assert.ok("status" in event);
328→      assert.ok("processed" in event);
329→      assert.ok("failed" in event);
330→      assert.ok("retrying" in event);
331→      assert.ok("remaining" in event);
332→    }
333→
334→    assert.equal(progressEvents[0].status, "processed");
335→    assert.equal(progressEvents[0].processed, 1);
336→    assert.equal(progressEvents[0].remaining, 1);
337→
338→    assert.equal(progressEvents[1].status, "processed");
339→    assert.equal(progressEvents[1].processed, 2);
340→    assert.equal(progressEvents[1].remaining, 0);
341→  });
342→
343→  it("should report retry progress events", async () => {
344→    const source = new Queue(["flaky"]);
345→    const progressEvents = [];
346→
347→    let callCount = 0;
348→    const processor = async () => {
349→      callCount++;
350→      if (callCount === 1) throw new Error("retry me");
351→      return "ok";
352→    };
353→
354→    const pipeline = new Pipeline({
355→      source,
356→      processor,
357→      maxRetries: 3,
358→      backoff: new ExponentialBackoff({ baseMs: 0 }),
359→      onProgress: (event) => progressEvents.push(event),
360→    });
361→
362→    await pipeline.run();
363→
364→    // Should have: 1 retry event + 1 processed event
365→    const retryEvents = progressEvents.filter((e) => e.status === "retrying");
366→    const processedEvents = progressEvents.filter(
367→      (e) => e.status === "processed"
368→    );
369→    assert.equal(retryEvents.length, 1);
370→    assert.equal(processedEvents.length, 1);
371→    assert.equal(retryEvents[0].attempt, 1);
372→  });
373→
374→  it("should report dead-lettered progress events", async () => {
375→    const source = new Queue(["doomed"]);
376→    const progressEvents = [];
377→
378→    const processor = async () => {
379→      throw new Error("always fails");
380→    };
381→
382→    const pipeline = new Pipeline({
383→      source,
384→      processor,
385→      maxRetries: 1, // only 1 retry allowed
386→      backoff: new ExponentialBackoff({ baseMs: 0 }),
387→      onProgress: (event) => progressEvents.push(event),
388→    });
389→
390→    await pipeline.run();
391→
392→    const dlqEvents = progressEvents.filter(
393→      (e) => e.status === "dead-lettered"
394→    );
395→    assert.equal(dlqEvents.length, 1);
396→    assert.equal(dlqEvents[0].item, "doomed");
397→    assert.ok(dlqEvents[0].error instanceof Error);
398→  });
399→});
400→
401→// =============================================================================
402→// TDD CYCLE 8 (RED→GREEN): Pipeline — final summary
403→// After all items are processed, the pipeline should return a summary object.
404→// =============================================================================
405→
406→describe("Pipeline — final summary", () => {
407→  it("should include all summary fields and timing info", async () => {
408→    const source = new Queue(["a", "b"]);
409→    const processor = mock.fn(async (item) => item);
410→
411→    const pipeline = new Pipeline({
412→      source,
413→      processor,
414→      maxRetries: 3,
415→      backoff: new ExponentialBackoff({ baseMs: 0 }),
416→    });
417→
418→    const summary = await pipeline.run();
419→
420→    assert.equal(summary.totalItems, 2);
421→    assert.equal(summary.processed, 2);
422→    assert.equal(summary.failed, 0);
423→    assert.equal(summary.retried, 0);
424→    assert.equal(summary.deadLettered, 0);
425→    assert.equal(typeof summary.durationMs, "number");
426→    assert.ok(summary.durationMs >= 0);
427→    assert.deepEqual(summary.deadLetteredItems, []);
428→  });
429→
430→  it("should include dead-lettered items in the summary", async () => {
431→    const source = new Queue(["bad1", "bad2"]);
432→    const processor = async () => {
433→      throw new Error("nope");
434→    };
435→
436→    const pipeline = new Pipeline({
437→      source,
438→      processor,
439→      maxRetries: 0, // no retries — immediately dead-letter
440→      backoff: new ExponentialBackoff({ baseMs: 0 }),
441→    });
442→
443→    const summary = await pipeline.run();
444→
445→    assert.equal(summary.deadLettered, 2);
446→    assert.equal(summary.deadLetteredItems.length, 2);
447→    assert.equal(summary.deadLetteredItems[0].item, "bad1");
448→    assert.equal(summary.deadLetteredItems[1].item, "bad2");
449→  });
450→});
451→
452→// =============================================================================
453→// TDD CYCLE 9 (RED→GREEN): Mockability — all queue and processor operations
454→// Verify that the pipeline works with custom/mocked queue implementations.
455→// =============================================================================
456→
457→describe("Pipeline — mockability", () => {
458→  it("should work with a custom queue implementation", async () => {
459→    // A custom queue wrapping an array — proves the pipeline interface is mockable
460→    const customQueue = {
461→      _items: ["x", "y"],
462→      dequeue() {
463→        return this._items.shift();
464→      },
465→      isEmpty() {
466→        return this._items.length === 0;
467→      },
468→      size() {
469→        return this._items.length;
470→      },
471→    };
472→
473→    const processor = mock.fn(async (item) => item.toUpperCase());
474→
475→    const pipeline = new Pipeline({
476→      source: customQueue,
477→      processor,
478→      maxRetries: 1,
479→      backoff: new ExponentialBackoff({ baseMs: 0 }),
480→    });
481→
482→    const summary = await pipeline.run();
483→    assert.equal(summary.processed, 2);
484→    assert.equal(processor.mock.calls.length, 2);
485→  });
486→
487→  it("should work with a mock processor that tracks calls", async () => {
488→    const source = new Queue(["item1", "item2"]);
489→    const results = [];
490→    const processor = async (item) => {
491→      results.push(item);
492→      return `result:${item}`;
493→    };
494→
495→    const pipeline = new Pipeline({
496→      source,
497→      processor,
498→      maxRetries: 3,
499→      backoff: new ExponentialBackoff({ baseMs: 0 }),
500→    });
501→
502→    await pipeline.run();
503→    assert.deepEqual(results, ["item1", "item2"]);
504→  });
505→
506→  it("should allow mocking the sleep function for testing backoff", async () => {
507→    const source = new Queue(["item"]);
508→    const sleepCalls = [];
509→
510→    let attempt = 0;
511→    const processor = async () => {
512→      attempt++;
513→      if (attempt <= 2) throw new Error("fail");
514→      return "ok";
515→    };
516→
517→    const pipeline = new Pipeline({
518→      source,
519→      processor,
520→      maxRetries: 5,
521→      backoff: new ExponentialBackoff({ baseMs: 50 }),
522→      sleepFn: async (ms) => sleepCalls.push(ms),
523→    });
524→
525→    await pipeline.run();
526→    // 2 retries = 2 sleep calls: 50, 100
527→    assert.deepEqual(sleepCalls, [50, 100]);
528→  });
529→});
530→
531→// =============================================================================
532→// TDD CYCLE 10 (REFACTOR): Edge cases
533→// =============================================================================
534→
535→describe("Pipeline — edge cases", () => {
536→  it("should handle empty queue gracefully", async () => {
537→    const source = new Queue();
538→    const processor = mock.fn(async (item) => item);
539→
540→    const pipeline = new Pipeline({
541→      source,
542→      processor,
543→      maxRetries: 3,
544→      backoff: new ExponentialBackoff({ baseMs: 0 }),
545→    });
546→
547→    const summary = await pipeline.run();
548→    assert.equal(summary.totalItems, 0);
549→    assert.equal(summary.processed, 0);
550→    assert.equal(summary.failed, 0);
551→    assert.equal(processor.mock.calls.length, 0);
552→  });
553→
554→  it("should handle processor returning falsy values", async () => {
555→    const source = new Queue([1, 2]);
556→    // Returns null/0/false — should still count as success
557→    const processor = async () => null;
558→
559→    const pipeline = new Pipeline({
560→      source,
561→      processor,
562→      maxRetries: 3,
563→      backoff: new ExponentialBackoff({ baseMs: 0 }),
564→    });
565→
566→    const summary = await pipeline.run();
567→    assert.equal(summary.processed, 2);
568→    assert.equal(summary.failed, 0);
569→  });
570→
571→  it("should handle maxRetries=0 (no retries at all)", async () => {
572→    const source = new Queue(["item"]);
573→    const processor = async () => {
574→      throw new Error("fail");
575→    };
576→
577→    const pipeline = new Pipeline({
578→      source,
579→      processor,
580→      maxRetries: 0,
581→      backoff: new ExponentialBackoff({ baseMs: 0 }),
